sql:
SELECT instance_id
FROM instances
WHERE upfront_cost = (SELECT MAX(upfront_cost) FROM instances);

SELECT instance_status, COUNT(*) AS instance_count
FROM instances
GROUP BY instance_status;

SELECT instance_id
FROM instances
ORDER BY instance_id;

SELECT AVG(estimated_monthly_savings) AS average_net_savings
FROM recommendations
WHERE implementation_status = 'Implemented';

external_knowledge:
- 'matured over time' refers to instances older than 90 days; 
- 'surge in usage' refers to an increasing usage trend; 
- 'yet to be upgraded' refers to instances with a pending implementation status for the recommended instance type; 
- 'proposed replacements' refer to the recommended instance types for RI purchase.
